import{_ as a,c as i}from"./app.e53bf642.js";const e={},h=i('<h1 id="\u77E5\u8BC6\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u77E5\u8BC6\u7BA1\u7406" aria-hidden="true">#</a> \u77E5\u8BC6\u7BA1\u7406</h1><h2 id="\u7B14\u8BB0\u7684\u8BEF\u533A" tabindex="-1"><a class="header-anchor" href="#\u7B14\u8BB0\u7684\u8BEF\u533A" aria-hidden="true">#</a> \u7B14\u8BB0\u7684\u8BEF\u533A</h2><h3 id="\u5728\u4F60\u638C\u63E1\u4E86\u751F\u4EA7\u529B\u6280\u80FD\u4E4B\u524D-\u751F\u4EA7\u529B\u5DE5\u5177\u90FD\u662F\u65E0\u7528\u7684" tabindex="-1"><a class="header-anchor" href="#\u5728\u4F60\u638C\u63E1\u4E86\u751F\u4EA7\u529B\u6280\u80FD\u4E4B\u524D-\u751F\u4EA7\u529B\u5DE5\u5177\u90FD\u662F\u65E0\u7528\u7684" aria-hidden="true">#</a> \u5728\u4F60\u638C\u63E1\u4E86\u751F\u4EA7\u529B\u6280\u80FD\u4E4B\u524D\uFF0C\u751F\u4EA7\u529B\u5DE5\u5177\u90FD\u662F\u65E0\u7528\u7684</h3><p>\u6211\u4EEC\u4E0D\u4EC5\u662F\u5728\u4F7F\u7528\u5DE5\u5177\uFF0C\u8FD8\u662F\u5728\u6539\u8FDB\u81EA\u5DF1\u7684\u5DE5\u4F5C\u6D41\u3002\u591A\u6570\u65F6\u5019\u4E0D\u662F\u5DE5\u5177\u4E0D\u597D\u7528\uFF0C\u800C\u662F\u7F3A\u5C11\u5DE5\u4F5C\u6D41\u7A0B\u7BA1\u7406\u3002 \u6240\u4EE5\u9700\u8981\u5728\u4E4E\u7684\u4E0D\u662F\u5DE5\u5177\uFF0C\u800C\u662F\u5DE5\u5177\u80CC\u540E\u7684\u65B9\u6CD5\u8BBA\u3002\u8BB8\u591A\u4EBA\u8FF7\u5931\u5728\u5BFB\u627E\u65B0\u5DE5\u5177\u800C\u6CA1\u6709\u53BB\u5EFA\u7ACB\u81EA\u5DF1\u7684\u5DE5\u4F5C\u6D41\u6846\u67B6\u3002 \u5148\u5173\u6CE8\u65B9\u6CD5\uFF0C\u800C\u4E0D\u662F\u5DE5\u5177\u672C\u8EAB\u3002\u5F53\u4F60\u6709\u4E86\u65B9\u6CD5\uFF0C\u5BF9\u5DE5\u5177\u7684\u53D6\u820D\u5C31\u4F1A\u5F88\u660E\u786E\u4E86\u3002</p><h3 id="\u5199\u4F5C\u4E0D\u662F\u601D\u8003\u7684\u7ED3\u679C-\u800C\u662F\u60F3\u6CD5\u7684\u5A92\u4ECB" tabindex="-1"><a class="header-anchor" href="#\u5199\u4F5C\u4E0D\u662F\u601D\u8003\u7684\u7ED3\u679C-\u800C\u662F\u60F3\u6CD5\u7684\u5A92\u4ECB" aria-hidden="true">#</a> \u5199\u4F5C\u4E0D\u662F\u601D\u8003\u7684\u7ED3\u679C\uFF0C\u800C\u662F\u60F3\u6CD5\u7684\u5A92\u4ECB</h3><p>\u9700\u8981\u4E00\u79CD\u65B9\u6CD5\u6765\u7EC4\u7EC7\u81EA\u5DF1\u7684\u601D\u60F3\uFF0C\u8DDF\u8E2A\u6240\u6D88\u8D39\u7684\u4FE1\u606F\u3002 \u5199\u4F5C\u53EF\u4EE5\u66F4\u597D\u7684\u63D0\u9AD8\u4E00\u4E2A\u4EBA\u7684\u601D\u7EF4\uFF0C\u56E0\u4E3A\u5B83\u8FEB\u4F7F\u4F60\u4ECE\u66F4\u6DF1\u7684\u5C42\u6B21\u53BB\u9605\u8BFB\u3002\u4EC5\u4EC5\u9605\u8BFB\u4E0D\u610F\u5473\u7740\u4F60\u6709\u66F4\u591A\u6216\u66F4\u597D\u7684\u60F3\u6CD5\u3002 \u5F53\u4F60\u6D88\u8D39\u4FE1\u606F\u7684\u65F6\u5019\uFF0C\u62E5\u6709\u4E00\u4E2A\u660E\u786E\u7684\u3001\u5207\u5B9E\u7684\u76EE\u6807\u4F1A\u5B8C\u5168\u6539\u53D8\u4F60\u5904\u7406\u4FE1\u606F\u7684\u65B9\u5F0F\u3002</p><h2 id="\u77E5\u8BC6\u7684\u5B9A\u4E49\u548C\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u77E5\u8BC6\u7684\u5B9A\u4E49\u548C\u7BA1\u7406" aria-hidden="true">#</a> \u77E5\u8BC6\u7684\u5B9A\u4E49\u548C\u7BA1\u7406</h2><h3 id="\u4EC0\u4E48\u662F\u77E5\u8BC6" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u77E5\u8BC6" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u77E5\u8BC6</h3><p>\u77E5\u8BC6\u662F\u7528\u4E8E\u751F\u4EA7\u7684\u4FE1\u606F\uFF08\u6709\u610F\u4E49\u7684\u4FE1\u606F\uFF09\u3002</p><p><strong>\u77E5\u8BC6\u662F\u4EBA\u7C7B\u7279\u6709\u7684\u8D44\u6E90\u3002\u4E66\u4E0A\u6CA1\u6709\u77E5\u8BC6\uFF0C\u4E66\u4E0A\u53EA\u6709\u4FE1\u606F\uFF1B\u77E5\u8BC6\u662F\u5728\u7279\u6B8A\u7684\u5DE5\u4F5C\u548C\u884C\u52A8\u4E2D\u8FD0\u7528\u4FE1\u606F\u7684\u80FD\u529B\u3002</strong></p><p>\u6280\u672F\u662F\u5728\u5DE5\u4F5C\u4E2D\u8FD0\u7528\u81EA\u7136\u79D1\u5B66\uFF0C\u662F\u77E5\u8BC6\u7684\u4E00\u79CD\u3002--1964\uFF0C\u5FB7\u9C81\u514B\u300A\u6210\u679C\u7BA1\u7406\u300B</p><h3 id="\u77E5\u8BC6\u7684\u7279\u70B9-\u96BE\u4EE5\u88AB\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u77E5\u8BC6\u7684\u7279\u70B9-\u96BE\u4EE5\u88AB\u7BA1\u7406" aria-hidden="true">#</a> \u77E5\u8BC6\u7684\u7279\u70B9 - \u96BE\u4EE5\u88AB\u7BA1\u7406</h3><ol><li>\u4EE3\u8868\u67D0\u79CD\u6743\u529B\u4E0E\u4F18\u52BF\uFF0C\u4EBA\u4EEC\u5E76\u4E0D\u662F\u968F\u65F6\u613F\u610F\u5171\u4EAB\u6240\u6709\u7684\u77E5\u8BC6\u4E0E\u7ECF\u9A8C\uFF0C\u9700\u8981\u8BBE\u8BA1\u673A\u5236\u6765\u542F\u53D1</li><li>\u5177\u6709\u6D41\u52A8\u6027\uFF0C\u7EC4\u7EC7\u5185\u90E8\u4EBA\u5458\u4F1A\u6D41\u52A8\uFF0C\u4E2A\u4EBA\u5219\u4F1A\u9057\u5FD8</li><li>\u788E\u7247\u5316\uFF0C\u6BD4\u8F83\u6563\u4E71\u3001\u7ECF\u5E38\u9057\u6F0F\u5E76\u4E14\u9700\u8981\u4E0D\u505C\u66F4\u65B0</li><li>\u65E0\u6CD5\u5FEB\u901F\u8BC4\u4F30\u5176\u4EF7\u503C\u4EE5\u53CA\u5229\u76CA\u56DE\u62A5</li></ol><h3 id="\u4EC0\u4E48\u662F\u77E5\u8BC6\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u77E5\u8BC6\u7BA1\u7406" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u77E5\u8BC6\u7BA1\u7406</h3><p>\u77E5\u8BC6\u7BA1\u7406\u7684\u7ECF\u5178\u5355\u884C\u5B9A\u4E49\u662F\u7531 Tom Davenport \u5728\u65E9\u671F\u63D0\u51FA\u7684(Davenport\uFF0C1994) : <strong>\u300C\u77E5\u8BC6\u7BA1\u7406\u662F\u83B7\u53D6\u3001\u5206\u914D\u548C\u6709\u6548\u5229\u7528\u77E5\u8BC6\u7684\u8FC7\u7A0B\u3002\u300D</strong></p><p>\u4E00\u5957\u80FD\u5C06\u83B7\u53D6\u5230\u7684\u4FE1\u606F\u8F6C\u5316\u4E3A\u77E5\u8BC6\u7684\u7CFB\u7EDF\u3002\u80FD\u6301\u7EED\u5730\u3001\u666E\u904D\u5730\u6536\u96C6\u300C\u663E\u6027\u4E0E\u9690\u6027\u77E5\u8BC6\u300D\uFF0C\u8FDB\u4E00\u6B65\u8F6C\u5316\u6210\u300C\u4F01\u4E1A\u6587\u5316\u300D\u6216\u300C\u4E2A\u4EBA\u54C1\u724C\u300D\uFF0C\u8BA9\u4EBA\u4EEC\u66F4\u80FD\u6CE8\u91CD\u5728\u300C\u4FE1\u606F\u7684\u4EA4\u6362\u300D\uFF0C\u900F\u8FC7\u4E92\u52A8\u7684\u4FE1\u606F\uFF0C\u300C\u518D\u521B\u9020\u300D\u77E5\u8BC6\u7684\u4EF7\u503C\u3002</p><p>\u91CD\u8981\u7684\u662F\uFF1A</p><ul><li>\u9AD8\u8D28\u91CF\u7684\u4FE1\u606F\u83B7\u53D6</li><li>\u9AD8\u6548\u7387\u7684\u77E5\u8BC6\u8F6C\u5316</li><li>\u89C4\u8303\u7684\u7CFB\u7EDF</li><li>\u521B\u5EFA\u8FDE\u63A5\uFF0C\u6FC0\u53D1\u65B0\u7684\u77E5\u8BC6</li></ul><h3 id="\u77E5\u8BC6\u7BA1\u7406\u7684\u610F\u4E49" tabindex="-1"><a class="header-anchor" href="#\u77E5\u8BC6\u7BA1\u7406\u7684\u610F\u4E49" aria-hidden="true">#</a> \u77E5\u8BC6\u7BA1\u7406\u7684\u610F\u4E49</h3><p>\u5F7C\u5F97 \xB7 \u5FB7\u9C81\u514B\u5728 1965 \u5E74\u9884\u8A00\uFF1A\u77E5\u8BC6\u5C06\u53D6\u4EE3\u571F\u5730\u3001\u52B3\u52A8\u3001\u8D44\u672C\u4E0E\u673A\u5668\u8BBE\u5907\uFF0C\u6210\u4E3A\u6700\u91CD\u8981\u7684\u751F\u4EA7\u56E0\u7D20\u3002\u4ED6\u8BA4\u4E3A\uFF0C21 \u4E16\u7EAA\u7684\u7EC4\u7EC7\uFF0C<strong>\u6700\u6709\u4EF7\u503C\u7684\u8D44\u4EA7\u662F\u7EC4\u7EC7\u5185\u7684\u77E5\u8BC6\u5DE5\u4F5C\u8005\u548C\u4ED6\u4EEC\u7684\u751F\u4EA7\u529B</strong>\u3002</p><p>\u5728\u4FE1\u606F\u65F6\u4EE3\u91CC\uFF0C\u77E5\u8BC6\u5DF2\u6210\u4E3A\u6700\u4E3B\u8981\u7684\u8D22\u5BCC\u6765\u6E90\uFF0C\u800C\u77E5\u8BC6\u5DE5\u4F5C\u8005\u5C31\u662F\u6700\u6709\u751F\u547D\u529B\u7684\u8D44\u4EA7\uFF0C\u7EC4\u7EC7\u548C\u4E2A\u4EBA\u7684\u6700\u91CD\u8981\u4EFB\u52A1\u5C31\u662F\u5BF9\u77E5\u8BC6\u8FDB\u884C\u7BA1\u7406\u3002<strong>\u77E5\u8BC6\u7BA1\u7406\u5C06\u4F7F\u7EC4\u7EC7\u548C\u4E2A\u4EBA\u5177\u6709\u66F4\u5F3A\u7684\u7ADE\u4E89\u5B9E\u529B\uFF0C\u5E76\u505A\u51FA\u66F4\u597D\u5730\u51B3\u7B56</strong>\u3002</p><p>Andrew Hunt \u5EFA\u8BAE\u50CF\u7BA1\u7406\u91D1\u878D\u6295\u8D44\u7EC4\u5408\u4E00\u6837\u6765\u7BA1\u7406\u77E5\u8BC6</p><ol><li>\u5B9A\u671F\u6295\u8D44 \u2014\u2014 \u517B\u6210\u575A\u6301\u5B66\u4E60\u7684\u4E60\u60EF</li><li>\u957F\u671F\u6295\u8D44\uFF0C\u591A\u5143\u5316\u662F\u5173\u952E \u2014\u2014 \u4E13\u6CE8\u773C\u4E0B\u7684\u4E8B\u60C5\uFF0C\u4F46\u4E5F\u8981\u6CE8\u610F\u66F4\u5E7F\u6CDB\u7684\u8303\u56F4</li><li>\u7BA1\u7406\u98CE\u9669 \u2014\u2014 \u4E0D\u8981\u628A\u300C\u9E21\u86CB\u90FD\u653E\u5728\u4E00\u4E2A\u7BEE\u5B50\u91CC\u300D\uFF0C\u4E5F\u8981\u907F\u514D\u4F4E\u98CE\u9669\u4F4E\u56DE\u62A5</li><li>\u8BBE\u6CD5\u4F4E\u4E70\u9AD8\u5356\uFF0C\u83B7\u53D6\u6700\u5927\u5229\u6DA6 \u2014\u2014 \u5B66\u4E60\u65B0\u5174\u6280\u672F\u6216\u8005\u9002\u7528\u9762\u9010\u6E10\u5E7F\u7684\u6280\u672F</li><li>\u5468\u671F\u6027\u7684\u8BC4\u4F30\u548C\u5E73\u8861 \u2014\u2014 \u5B9A\u671F\u8BC4\u4F30\u54EA\u4E9B\u662F\u503C\u5F97\u5B66\u4E60\u548C\u5173\u6CE8\u7684</li></ol><h3 id="\u77E5\u8BC6\u7684\u5206\u7C7B" tabindex="-1"><a class="header-anchor" href="#\u77E5\u8BC6\u7684\u5206\u7C7B" aria-hidden="true">#</a> \u77E5\u8BC6\u7684\u5206\u7C7B</h3><h4 id="\u6839\u636E\u9002\u7528\u6027\u5206\u7C7B" tabindex="-1"><a class="header-anchor" href="#\u6839\u636E\u9002\u7528\u6027\u5206\u7C7B" aria-hidden="true">#</a> \u6839\u636E\u9002\u7528\u6027\u5206\u7C7B</h4><p>\u5FB7\u9C81\u514B\u300A\u77E5\u8BC6\u793E\u4F1A\u300B\u4E00\u4E66\u4E2D\uFF0C\u4ED6\u5C06\u77E5\u8BC6\u5206\u4E3A\uFF1A</p><ul><li>\u7EFC\u5408\u6027\u77E5\u8BC6\uFF1A\u5373\u6211\u4EEC\u4F20\u7EDF\u800C\u8A00\u7684\u667A\u6167\uFF0C\u4E3B\u8981\u5728\u4E8E\u57F9\u517B\u6709\u6559\u517B\u3001\u9053\u5FB7\u7684\u4EBA\uFF0C\u76EE\u7684\u662F\u4E3A\u4E86\u81EA\u77E5</li><li>\u4E13\u5C5E\u77E5\u8BC6\uFF1A\u5373\u884C\u52A8\u4E2D\u53EF\u4EE5\u8BC1\u5B9E\u5BF9\u884C\u52A8\u7ED3\u679C\u6709\u6548\u7684\u4FE1\u606F\uFF0C\u4E3B\u8981\u5728\u4E8E\u5DE5\u4F5C\u7814\u7A76\u3001\u5DE5\u4F5C\u5206\u6790\u548C\u5DE5\u4F5C\u7BA1\u7406\u4E0A</li></ul><p>\u4E3E\u4E2A\u7B80\u5355\u7684\u4F8B\u5B50\uFF0C\u5982\u679C\u4F60\u88AB\u8FEB\u6D41\u843D\u8352\u5C9B\uFF0C\u5927\u6982\u7387\u5E0C\u671B\u548C\u8D1D\u7237\u4E00\u8D77\u751F\u5B58\uFF0C\u800C\u4E0D\u662F\u548C\u82CF\u683C\u62C9\u5E95\u6216\u8005\u5B54\u5B50\uFF0C\u56E0\u4E3A\u540E\u8005\u867D\u7136\u6709\u9053\u5FB7\u548C\u4FEE\u517B\uFF0C\u4F46\u662F\u524D\u8005\u5173\u4E8E\u751F\u5B58\u7684\u4E13\u5C5E\u77E5\u8BC6\u80FD\u89E3\u51B3\u6211\u4EEC\u5403\u996D\u548C\u7761\u89C9\u7684\u5177\u4F53\u95EE\u9898\u3002\u6B63\u662F\u7531\u4E8E\u8FD9\u79CD\u89C6\u89D2\u7684\u8F6C\u5316\uFF0C\u624D\u6784\u5EFA\u4E86\u5DE5\u4E1A\u9769\u547D\u4E4B\u540E\u7684\u65B0\u578B\u793E\u4F1A\uFF0C\u8D4B\u4E88\u4E86\u6211\u4EEC\u77E5\u8BC6\u548C\u4E13\u5BB6\u7684\u6743\u5229</p><h4 id="\u638C\u63E1\u6839\u636E\u77E5\u8BC6\u7684\u6027\u8D28\u5212\u5206\u7684\u56DB\u79CD\u7C7B\u578B\u7684\u6982\u5FF5" tabindex="-1"><a class="header-anchor" href="#\u638C\u63E1\u6839\u636E\u77E5\u8BC6\u7684\u6027\u8D28\u5212\u5206\u7684\u56DB\u79CD\u7C7B\u578B\u7684\u6982\u5FF5" aria-hidden="true">#</a> \u638C\u63E1\u6839\u636E\u77E5\u8BC6\u7684\u6027\u8D28\u5212\u5206\u7684\u56DB\u79CD\u7C7B\u578B\u7684\u6982\u5FF5</h4><ul><li>\u4E8B\u5B9E\u77E5\u8BC6\uFF1A\u77E5\u9053\u662F\u4EC0\u4E48\u7684\u77E5\u8BC6\uFF0C\u662F\u5173\u4E8E\u5386\u53F2\u4E8B\u5B9E\u3001\u7ECF\u9A8C\u603B\u7ED3\u3001\u7EDF\u8BA1\u6570\u636E\u7684\u77E5\u8BC6\u3002Know what</li><li>\u539F\u7406\u77E5\u8BC6\uFF1A\u77E5\u9053\u4E3A\u4EC0\u4E48\u7684\u77E5\u8BC6\uFF0C\u662F\u5173\u4E8E\u4E8B\u7269\u7684\u539F\u7406\u548C\u5BA2\u89C2\u89C4\u5F8B\u65B9\u9762\u7684\u77E5\u8BC6\uFF0C\u901A\u5E38\u5C5E\u4E8E\u79D1\u5B66\u8303\u7574\u3002Know\u2014why</li><li>\u6280\u80FD\u77E5\u8BC6\uFF1A\u77E5\u9053\u600E\u4E48\u505A\u7684\u77E5\u8BC6\uFF0C\u662F\u5173\u4E8E\u6280\u827A\u3001\u6280\u5DE7\u3001\u8BC0\u7A8D\u548C\u80FD\u529B\u65B9\u9762\u7684\u77E5\u8BC6\uFF0C\u5C5E\u4E8E\u6280\u672F\u8303\u7574\u3002Know\u2014how</li><li>\u4EBA\u529B\u77E5\u8BC6\uFF1A\u77E5\u9053\u662F\u8C01\u7684\u77E5\u8BC6\uFF0C\u662F\u5173\u4E8E\u8C01\u77E5\u9053\u4EC0\u4E48\u4EE5\u53CA\u8C01\u77E5\u9053\u5982\u4F55\u505A\u4EC0\u4E48\u7684\u77E5\u8BC6\uFF0C\u5305\u542B\u4E86\u67D0\u79CD\u7279\u5B9A\u7684\u793E\u4F1A\u5173\u7CFB\u4EE5\u53CA\u793E\u4F1A\u5206\u5DE5\u3001\u77E5\u9053\u8005\u7684\u7279\u957F\u4E0E\u6C34\u5E73\uFF0C\u5C5E\u4E8E\u7ECF\u9A8C\u548C\u5224\u65AD\u7684\u8303\u7574\u3002Know who</li></ul><h4 id="\u6839\u636E\u77E5\u8BC6\u7684\u8868\u73B0\u5F62\u5F0F\u5212\u5206" tabindex="-1"><a class="header-anchor" href="#\u6839\u636E\u77E5\u8BC6\u7684\u8868\u73B0\u5F62\u5F0F\u5212\u5206" aria-hidden="true">#</a> \u6839\u636E\u77E5\u8BC6\u7684\u8868\u73B0\u5F62\u5F0F\u5212\u5206</h4><ul><li>\u663E\u6027\u77E5\u8BC6(Explicit Knowledge)\uFF1A\u4E5F\u79F0\u7F16\u7801\u77E5\u8BC6\uFF0C\u6307\u53EF\u4EE5\u7528\u8BED\u8A00\u3001\u6587\u5B57\u3001\u6570\u5B57\u7B49\u65B9\u5F0F\u8FDB\u884C\u8868\u8FBE\u4ECE\u800C\u6613\u4E8E\u6C9F\u901A\u548C\u5171\u4EAB\u7684\u77E5\u8BC6\u3002\u5982\u4EE5\u6587\u4EF6\u3001\u624B\u518C\u3001\u62A5\u544A\u3001\u5730\u56FE\u7B49\u65B9\u5F0F\u5448\u73B0\u7684\u77E5\u8BC6\u3002Know-how/know-who</li><li>\u9690\u6027\u77E5\u8BC6(Tacit Knowledge)\uFF1A\u4E5F\u79F0\u672A\u7F16\u7801\u77E5\u8BC6\uFF0C\u6307\u96BE\u4EE5\u8868\u8FBE\u3001\u9AD8\u5EA6\u4E2A\u6027\u5316\u3001\u96BE\u4EE5\u6C9F\u901A\u548C\u5171\u4EAB\u7684\u77E5\u8BC6\u3002\u5982\u7ECF\u8425\u8005\u6216\u5458\u5DE5\u7684\u7ECF\u9A8C\u3001\u6280\u672F\u8BC0\u7A8D\u3001\u76F4\u89C9\u7B49\u3002Know-what/know-why <ul><li>\u6280\u80FD\u7C7B\u9690\u6027\uFF1A\u975E\u6B63\u5F0F\u7684\u3001\u96BE\u4EE5\u8868\u8FBE\u7684\u6280\u80FD\u3001\u6280\u5DE7\u3001\u7ECF\u9A8C\u548C\u8BC0\u7A8D\u7B49\uFF1B</li><li>\u8BA4\u77E5\u7C7B\u9690\u6027\uFF1A\u6D1E\u5BDF\u529B\u3001\u76F4\u89C9\u3001\u611F\u609F\u3001\u4EF7\u503C\u89C2\u3001\u5FC3\u667A\u6A21\u5F0F\u3001\u56E2\u961F\u7684\u9ED8\u5951\u548C\u7EC4\u7EC7\u6587\u5316\u7B49\u3002</li></ul></li></ul><p>https://help.flomoapp.com/thinking/area.html https://www.bilibili.com/video/BV1Vq4y1X7i8/</p>',33);function r(l,d){return h}var t=a(e,[["render",r],["__file","zhishiguanli.html.vue"]]);export{t as default};
